import React from "react";
import productsData from "../data/ProductData"; // adjust path

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  return (
    <section
      style={{
        padding: "40px 60px", // spacing from sides
        maxWidth: "1200px",   // keeps content centered
        margin: "0 auto",
      }}
    >
      <h2 style={{ textAlign: "center", marginBottom: "30px" }}>
        🔥 Popular Products
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)", // 4 per row
          gap: "25px",
        }}
      >
        {popularItems.map((item) => (
          <div
            key={item.id}
            style={{
              border: "1px solid #eee",
              borderRadius: "12px",
              padding: "12px",
              textAlign: "center",
              background: "#fff",
              boxShadow: "0 2px 5px rgba(0,0,0,0.08)",
              display: "flex",
              flexDirection: "column",
              justifyContent: "space-between",
              maxWidth:"220px",
              margin:"0 auto"
            }}
          >
            {/* Image */}
            <img
              src={item.image}
              alt={item.name}
              style={{
                width: "100%",
                height: "180px",
                objectFit: "contain",
                marginBottom: "15px",
              }}
            />

            {/* Product Name */}
            <h3
              style={{
                fontSize: "15px",
                margin: "10px 0",
                fontWeight: "600",
                color: "#333",
              }}
            >
              {item.name}
            </h3>

            {/* Price */}
            <p
              style={{
                color: "#e63946",
                fontWeight: "bold",
                fontSize: "16px",
                marginBottom: "15px",
              }}
            >
              {item.price}
            </p>

            {/* Buy Button */}
            <button
              style={{
                background: "#007bff",
                color: "#fff",
                border: "none",
                padding: "10px 0",
                borderRadius: "6px",
                cursor: "pointer",
                fontWeight: "500",
              }}
              onClick={() => console.log("Add to cart:", item.id)}
            >
              Buy Now
            </button>
          </div>
        ))}
      </div>
    </section>
  );
};

export default PopularProducts;
